package org.example;

import java.util.concurrent.BlockingQueue;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.atomic.AtomicInteger;

public class CircuitBreaker {
    ConcurrentHashMap<Long, Bucket> buckets;
    int windowTime;
    double failureRatio;
    int circuitCloseTime;
    int minRequests;
    CircuitState currentState;
    private volatile long openTime = -1;

    public CircuitBreaker(int windowTime, double failureRatio, int circuitCloseTime, int minRequests) {
        this.windowTime = windowTime;
        this.failureRatio = failureRatio;
        this.circuitCloseTime = circuitCloseTime;
        this.minRequests = minRequests;
        this.currentState = CircuitState.CLOSED;
        this.buckets = new ConcurrentHashMap<>();
    }

    public boolean call(Rpc rpc) {
        long now = currentTime();

        if (currentState == CircuitState.OPEN) {
            if (now - openTime >= circuitCloseTime) {
                currentState = CircuitState.HALF_OPEN;
            } else {
                return false;
            }
        }
        boolean success;

        try {
            success = rpc.call();
        } catch (Exception e) {
            success = false;
        }

        record(now, success);
        evaluate(now, success);

        return success;
    }

    private void record(long sec, boolean success) {
        Bucket bucket = buckets.computeIfAbsent(sec, k -> new Bucket());

        if (success) {
            bucket.success.incrementAndGet();
        } else {
            bucket.failures.incrementAndGet();
        }
        cleanup(sec);
    }

    private void cleanup(long now) {
        long limit = now - windowTime;

        for (Long key : buckets.keySet()) {
            if (key < limit) {
                buckets.remove(key);
            }
        }
    }

    private void evaluate(long now, boolean lastSuccess) {
        if (currentState == CircuitState.HALF_OPEN) {
            if (lastSuccess) {
                currentState = CircuitState.CLOSED;
                buckets.clear();
            } else {
                open(now);
            }
            return;
        }
        int successes = 0, failures = 0, total = 0;
        for (Bucket b: buckets.values()) {
            successes += b.success.get();
            failures += b.failures.get();
        }
        total = successes + failures;
        if (total < minRequests) return;
        double ratio = successes * 1d / total;
        if (ratio >= failureRatio) {
            open(now);
        }
    }

    private void open(long now) {
        currentState = CircuitState.OPEN;
        openTime = now;
    }

    private long currentTime() {
        return System.currentTimeMillis() / 1000;
    }
}

class Bucket {
    AtomicInteger failures, success;

    Bucket() {
        this.failures = new AtomicInteger();
        this.success = new AtomicInteger();
    }
}

class Request {
    public int time;
    public boolean isSucceeded;
}

enum CircuitState {
    OPEN,
    CLOSED,
    HALF_OPEN,
}

interface Rpc {
    boolean call();
}
