package circuit_breaker

import (
	"fmt"
	"math/rand/v2"
	"sync"
	"sync/atomic"
	"time"
)

// Implement simple circuit breaker given a rpc method.
// please consider the generic circuit breaker options like the following:
//
// * timeWindowSec - (10s) time sliding window size.
// * failureRatioThreshold - (50%) failure ratio threshold in which the circuit open
// * circuitCloseTimeSec - (5s) required time to circuit re-close
// * min requests - 10

var isCircuitOpen atomic.Value
var reqCnt, failCnt atomic.Int64

type NonBlockingQueue struct {
	sync.Mutex
	Items []time.Time
}

func (q *NonBlockingQueue) Push(item time.Time) {
	q.Lock()
	defer q.Unlock()
	q.Items = append(q.Items, item)
}

func (q *NonBlockingQueue) Pop() *time.Time {
	q.Lock()
	defer q.Unlock()
	if len(q.Items) == 0 {
		return nil
	}
	item := q.Items[0]
	q.Items = q.Items[1:]
	return &item
}

func (q *NonBlockingQueue) Front() *time.Time {
	q.Lock()
	defer q.Unlock()
	if len(q.Items) == 0 {
		return nil
	}
	item := q.Items[0]
	return &item
}

func CircuitBreaker() {
	isCircuitOpen.Store(false)
	ticker := time.NewTicker(time.Second * 1) // tickers are something to do repeatedly at regular intervals
	done := make(chan bool)
	queue := &NonBlockingQueue{
		Items: []time.Time{},
	}
	go func() {
		for {
			select {
			case <-done:
				return
			case t := <-ticker.C:
				fmt.Println("Tick at every second", t)
				evaluateCircuit(queue, t)
			}
		}
	}()

	time.Sleep(time.Minute * 1)
	ticker.Stop()
	done <- true
	fmt.Println("Ticker stopped")
}

func evaluateCircuit(queue *NonBlockingQueue, time time.Time) {
	queue.Push(time)
	// increase total count
	reqCnt.Add(1)
	// randomly get request status from downstream call
	if !isCircuitOpen.Load().(bool) {
		reqStatus := getRequestStatus()
		fmt.Println("called downstream, received status = ", reqStatus)
		if reqStatus != "PASS" {
			failCnt.Add(1)
		}
	}
	// calculate threshold
	threshold := failCnt.Load() * 100 / reqCnt.Load()
	fmt.Println("threshold is ", threshold)

	if threshold > 30 && reqCnt.Load() > 10 && !isCircuitOpen.Load().(bool) &&
		evaluateCircuitWindow(queue, time) {
		// open the circuit
		isCircuitOpen.Store(true)
		fmt.Println("circuit open")
		var wg sync.WaitGroup
		wg.Add(1)
		go evaluateCircuitToOpen(&wg)
	}
}

func evaluateCircuitWindow(queue *NonBlockingQueue, lastTime time.Time) bool {
	front := queue.Front()
	if lastTime.Second()-front.Second() >= 10 {
		queue.Pop()
		return true
	}
	return false
}

func evaluateCircuitToOpen(wg *sync.WaitGroup) {
	defer wg.Done()
	ticker := time.NewTicker(time.Second * 1)
	done := make(chan bool)

	go func() {
		for {
			select {
			case <-done:
				return
			case t := <-ticker.C:
				fmt.Println("Tick at", t)
			}
		}
	}()

	time.Sleep(time.Second * 5)
	ticker.Stop()
	done <- true
	isCircuitOpen.Store(false)
	fmt.Println("circuit closed")
}

/*
*Fn to return the request Status
 */
func getRequestStatus() string {
	rnd := rand.Int64() % 2
	if rnd == 1 {
		return "PASS"
	}
	return "FAIL"
}

